import json,sys,collections
sys.path.insert(0,'.')
from cost_model import CostModel, align

G=64
cm=CostModel(G)

def load(b):
    return [json.loads(l) for l in open(f"../input_data/requests_bucket_{b}.jsonl")]

def evaluate(reqs, recs):
    reqmap={r['request_id']:r for r in reqs}
    return cm.plan_metrics(reqmap, recs)

# global seq_align levels (<=8 across both). choose here.
def assign_shape(realalign, levels):
    for L in levels:
        if L>=realalign: return L
    return levels[-1]

def make_plan(reqs, levels, group_fn):
    # group_fn(r) -> key
    groups=collections.defaultdict(list)
    for r in reqs:
        groups[group_fn(r)].append(r)
    recs=[]; bid=0
    for key,rs in groups.items():
        bid+=1; batch_id=f"b-{bid:04d}"
        maxalign=max(align(r['prompt_len'],64) for r in rs)
        seq=assign_shape(maxalign,levels)
        for r in rs:
            recs.append({'request_id':r['request_id'],'batch_id':batch_id,
                'shape':{'seq_align':seq,'heads_align':32,'hidden_align':4096}})
    return recs, bid

levels=[128,256,384,512,704,1088,1536,2048]

for b in [1,2]:
    reqs=load(b)
    # strategy: group by (gen, align-level)
    def gf(r):
        return (r['gen_len'], assign_shape(align(r['prompt_len'],64),levels))
    recs,nb=make_plan(reqs,levels,gf)
    m=evaluate(reqs,recs)
    print(f"b{b} [gen,Slevel] nbatch={nb}: cost={m['cost']:.4e} pad={m['pad_ratio']:.4f} p95={m['p95_latency_ms']:.4e} seq={m['sequential_timecost']:.4e}")
EOF
